size(6cm);
pair A=(0,0),B=(0,5),C=(8,5),D=(8,0),E=(8,2),F=(5.5,5);
draw(A--B--C--D--A^^E--F);
label("$c$",A--B,W);
label("$d$",B--F,N);
label("$e$",E--F,SW);
label("$a$",E--D,dir(0));
label("$b$",D--A,S);
